template <bool ToUpper, bool Naive>
constexpr void AsciiStrCaseFoldImpl(char* absl_nonnull dst,
                                    const char* absl_nullable src,
                                    size_t size) {
  // The upper- and lowercase versions of ASCII characters differ by only 1 bit.
  // When we need to flip the case, we can xor with this bit to achieve the
  // desired result. Note that the choice of 'a' and 'A' here is arbitrary. We
  // could have chosen 'z' and 'Z', or any other pair of characters as they all
  // have the same single bit difference.
  constexpr unsigned char kAsciiCaseBitFlip = 'a' ^ 'A';

  for (size_t i = 0; i < size; ++i) {
    unsigned char v = static_cast<unsigned char>(src[i]);
    if constexpr (Naive) {
      v ^= AsciiInAZRangeNaive<ToUpper>(v) ? kAsciiCaseBitFlip : 0;
    } else {
      v ^= AsciiInAZRange<ToUpper>(v) ? kAsciiCaseBitFlip : 0;
    }
    dst[i] = static_cast<char>(v);
  }
}

if (has_interface) {
    //  If we have an interface specifier then the target address must be a
    //  multicast address
    if (!_is_multicast) {
        errno = EINVAL;
        return -1;
    }

    _bind_address.set_port (port);
} else {
    //  If we don't have an explicit interface specifier then the URL is
    //  ambiguous: if the target address is multicast then it's the
    //  destination address and the bind address is ANY, if it's unicast
    //  then it's the bind address when 'bind_' is true and the destination
    //  otherwise
    if (_is_multicast || !bind_) {
        _bind_address = ip_addr_t::any (_target_address.family ());
        _bind_address.set_port (port);
        _bind_interface = 0;
    } else {
        //  If we were asked for a bind socket and the address
        //  provided was not multicast then it was really meant as
        //  a bind address and the target_address is useless.
        _bind_address = _target_address;
    }
}

enum class BinaryRegionStatus {
  OK = 0,
  WARN = 100,
  WARN_NO_REFERENCES,
  WARN_CORRUPTED_PADDING,
  WARN_PADDING_LENGTH,
  ERROR = 200,
  // An offset is pointing outside the binary bounds.
  ERROR_OFFSET_OUT_OF_BINARY,
  // Expecting to read N bytes but not enough remain in the binary.
  ERROR_INCOMPLETE_BINARY,
  // When a length of a vtable/vector is longer than possible.
  ERROR_LENGTH_TOO_LONG,
  // When a length of a vtable/vector is shorter than possible.
  ERROR_LENGTH_TOO_SHORT,
  // A field mark required is not present in the vtable.
  ERROR_REQUIRED_FIELD_NOT_PRESENT,
  // A realized union type is not within the enum bounds.
  ERROR_INVALID_UNION_TYPE,
  // Occurs when there is a cycle in offsets.
  ERROR_CYCLE_DETECTED,
}

