if (bridge == sender_.get()) {
  // We previously cancelled the sender due to an input receiver closure
  // with an exception (or the closure of all input receivers without an
  // exception). Process the cancellation for the sender.
  CHECK_EQ(getSenderState(), ChannelState::CancellationTriggered);
  processSenderCancelled();
} else {
  // We previously cancelled this input receiver, either because the
  // consumer of the output receiver stopped consuming or because another
  // input receiver received an exception. Process the cancellation for
  // this input receiver.
  auto* receiver = static_cast<ChannelBridge<TValue>*>(bridge);
  CHECK_EQ(
      getReceiverState(receiver), ChannelState::CancellationTriggered);
  processReceiverCancelled(receiver, CloseResult());
}

class XdsServerServingStatusNotifierInterface {
 public:
  struct ServingStatusUpdate {
    grpc::Status status;
  };

  virtual ~XdsServerServingStatusNotifierInterface() = default;

  // \a uri contains the listening target associated with the notification. Note
  // that a single target provided to XdsServerBuilder can get resolved to
  // multiple listening addresses.
  // The callback is invoked each time there is an update to the serving status.
  // The API does not provide any guarantees around duplicate updates.
  // Status::OK signifies that the server is serving, while a non-OK status
  // signifies that the server is not serving.
  virtual void OnServingStatusUpdate(std::string uri,
                                     ServingStatusUpdate update) = 0;
}
